import { Review, ApiResponse } from '@/types';
import { mockReviews, mockPatients } from '@/data/mockData';
import { apiSuccess, apiError } from './api';

// In-memory store
let reviews = [...mockReviews];

export const reviewService = {
  async getDoctorReviews(doctorId: string): Promise<ApiResponse<Review[]>> {
    const doctorReviews = reviews
      .filter(r => r.doctorId === doctorId)
      .map(r => ({
        ...r,
        patient: mockPatients.find(p => p.id === r.patientId),
      }))
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());

    return apiSuccess(doctorReviews);
  },

  async createReview(data: {
    doctorId: string;
    patientId: string;
    appointmentId: string;
    rating: number;
    comment: string;
  }): Promise<ApiResponse<Review>> {
    // Check if review already exists for this appointment
    const existing = reviews.find(r => r.appointmentId === data.appointmentId);
    if (existing) {
      return apiError('Review already exists for this appointment');
    }

    const newReview: Review = {
      id: `rev-${Date.now()}`,
      ...data,
      createdAt: new Date().toISOString(),
    };

    reviews.push(newReview);

    return apiSuccess({
      ...newReview,
      patient: mockPatients.find(p => p.id === data.patientId),
    }, 'Review submitted');
  },

  async getAverageRating(doctorId: string): Promise<ApiResponse<{ average: number; count: number }>> {
    const doctorReviews = reviews.filter(r => r.doctorId === doctorId);
    const average = doctorReviews.length > 0
      ? doctorReviews.reduce((sum, r) => sum + r.rating, 0) / doctorReviews.length
      : 0;

    return apiSuccess({
      average: Math.round(average * 10) / 10,
      count: doctorReviews.length,
    });
  },
};
